             // Values over the limit are treated as the limit\n                this.printRow = Math.min(this.getVar(arg1), 24);\n                this.printCol = Math.min(this.getVar(arg2), 19);\n                break;\n\n            case 0x3B: // print _____________________ (literal string)\n                // The raw bytes are stored in instr.printBytes by the parser\n                // Draws to scene's pixel buffer using palette indices (0-3)\n                if (instr.printBytes && charset.loaded) {\n                    const targetScenes = this.getPrintTargetScenes();\n                    for (const targetScene of targetScenes) {\n                        // Convert character row/col to GM pixel coordinates (8x8 per char)\n                        const x = this.printCol * 8;\n                        const y = this.printRow * 8;\n                        // Draw using palette indices directly (0-3)\n                        charset.drawBytesToScene(targetScene, instr.printBytes, x, y, this.printFgColor, this.printBgColor);\n                    }\n                    // Advance to next row after printing (GM behavior)\n                    this.printRow++;\n                } else if (!charset.loaded) {\n                }\n                break;\n\n            case 0x3C: // print character of [a]\n                // arg2 = variable index containing GM character index (0-63)\n                // Draws to scene's pixel buffer using palette indices (0-3)\n                // Auto-advances printCol after each character (GM behavior)\n                if (charset.loaded) {\n                    const targetScenes = this.getPrintTargetScenes();\n                    const gmIndex = this.getVar(arg2) % 64; // Ensure 0-63 range\n                    for (const targetScene of targetScenes) {\n                        const x = this.printCol * 8;\n                        const y = this.printRow * 8;\n                        charset.drawCharToScene(targetScene, gmIndex, x, y, this.printFgColor, this.printBgColor);\n                    }\n                    // Advance column for next character\n                    this.printCol++;\n                }\n                break;\n\n            case 0x3D: // print value of [var]\n                // arg2 = variable index, prints the numeric value as text\n                // GM zero-pads to 3 digits (variables are 0-255)\n                // Draws to scene's pixel buffer using palette indices (0-3)\n                if (charset.loaded) {\n                    const targetScenes = this.getPrintTargetScenes();\n                    const value = this.getVar(arg2);\n                    const valueStr = value.toString().padStart(3, '0');\n                    for (const targetScene of targetScenes) {\n                        const x = this.printCol * 8;\n                        const y = this.printRow * 8;\n                        charset.drawStringToScene(targetScene, valueStr, x, y, this.printFgColor, this.printBgColor);\n                    }\n                }\n                break;\n\n            case 0x3E: // print color= 00 on 00\n                // arg1 = foreground slot (0-3), arg2 = background slot (0-3)\n                this.printFgColor = arg1;\n                this.printBgColor = arg2;\n                break;\n\n            case 0x3F: // print color=[a] on [a]\n                // arg1 = variable index for fg, arg2 = variable index for bg\n                this.printFgColor = this.getVar(arg1) % 16;\n                this.printBgColor = this.getVar(arg2) % 16;\n                break;\n\n            case 0x5B: // scoreX displays on sceneX\n                // arg1 = score index (0 or 1)\n                // arg2 = scene target (0=scene1, 1=scene2, 2=both)\n                // Note: This just sets where the score WILL display, doesn't render yet.\n                // Score only renders when \"add to score\" is executed.\n                {\n                    const scoreIdx = arg1;\n                    this.scoreScene[scoreIdx] = arg2;\n                    this.scoreVisible[scoreIdx] = true;\n                }\n                break;\n\n            case 0x5C: // print on scene\n                // Sets target scene for print operations\n                // arg2: 0=scene1, 1=scene2, 2=both\n                this.printScene = arg2;\n                break;\n\n            case 0x53: // clear scene X\n                // arg2 = scene number (1 or 2, stored as 0 or 1)\n                {\n                    const sceneIndex = arg2;\n                    if (this.scenes[sceneIndex]) {\n                        this.scenes[sceneIndex].clear();\n                    }\n                }\n                break;\n\n            case 0x56: // display other scene\n                // Toggle between scene 0 and scene 1\n                this.activeScene = this.activeScene === 0 ? 1 : 0;\n                break;\n\n            case 0x57: // pause for XX.X seconds\n                // arg2 = time value 1-255, with implied decimal before last digit\n                // So 15 = 1.5 seconds, 255 = 25.5 seconds, range is 0.1 to 25.5 seconds\n                if (!this.config.skipPauseInstructions) {\n                    const pauseSeconds = arg2 / 10;\n                    const pauseMs = pauseSeconds * 1000;\n                    this.pauseUntil = Date.now() + pauseMs;\n                }\n                break;\n\n            case 0x66: // screen update on/off\n                // GM bytecode: 0=on, 1=off (single-arg opcode uses arg2)\n                this.screenUpdateOn = (arg2 === 0);\n                break;\n\n            case 0x4D: // plot color X to scene Y\n                // arg1 = color index (0-3), arg2 = scene index (0 or 1)\n                this.plotColor = arg1 & 0x03;\n                this.plotScene = arg2 & 0x01;\n                break;\n\n            case 0x4E: // plot color [var] to scene Y\n                // arg1 = variable index for color, arg2 = scene index (0 or 1)\n                this.plotColor = this.getVar(arg1) & 0x03;\n                this.plotScene = arg2 & 0x01;\n                break;\n\n            case 0x4F: // plot a dot at x=XXX y=XXX (immediate values)\n                // arg1 = x coordinate, arg2 = y coordinate\n                // GM coordinates: x=12-171 visible, y=50-249 visible\n                // Scene coordinates: x=0-159 (fat pixels), y=0-199\n                {\n                    const scene = this.scenes[this.plotScene];\n                    if (scene) {\n                        // Convert GM coordinates to scene coordinates\n                        const sceneX = arg1 - 12;\n                        const sceneY = arg2 - 50;\n                        scene.setPixel(sceneX, sceneY, this.plotColor);\n                    }\n                }\n                break;\n\n            case 0x50: // plot a dot at x=[a] y=[a] (variable values)\n                // arg1 = variable index for x, arg2 = variable index for y\n                {\n                    const scene = this.scenes[this.plotScene];\n                    if (scene) {\n                        const gmX = this.getVar(arg1);\n                        const gmY = this.getVar(arg2);\n                        // Convert GM coordinates to scene coordinates\n                        const sceneX = gmX - 12;\n                        const sceneY = gmY - 50;\n                        scene.setPixel(sceneX, sceneY, this.plotColor);\n                    }\n                }\n                break;\n        }\n\n    }\n\n    // === HITBOX METHODS (320×200 COORDINATES) ===\n    // All hitboxes are returned in 320×200 screen coordinates.\n    // gmSprite.getHitboxes() expects base position in 320×200 space.\n\n    // Convert GM slot coordinates to 320×200 space\n    // Floor values to ensure integer pixel coordinates (positions can be fractional from movement)\n    _slotTo320(slot) {\n        return {\n            x: Math.floor((slot.x - 12) * 2),\n            y: Math.floor(slot.y - 50)\n        };\n    }\n\n    // Get hitboxes for a sprite slot (for collision detection)\n    // Each slot returns ONLY its own quad's hitbox:\n    //   - Parent slot (e.g., slot 4) → quad 0 only\n    //   - Subsprite slot (e.g., slot 5) → quad 1 only\n    // This allows GM games to check collisions with specific parts of multi-part sprites.\n    getHitboxes(slotIndex) {\n        const slot = this.sprites[slotIndex];\n\n        // If this slot has a sprite, it's a parent sprite - return ONLY quad 0\n        if (slot.spriteInstance) {\n            if (!slot.visible) return [];\n            const pos = this._slotTo320(slot);\n            return slot.spriteInstance.getHitboxes(pos.x, pos.y, 0);  // quad 0 only\n        }\n\n        // This slot doesn't have a spriteInstance - check if it's a subsprite slot\n        // Look backwards to find the parent sprite\n        for (let parentIdx = slotIndex - 1; parentIdx >= 0; parentIdx--) {\n            const parentSlot = this.sprites[parentIdx];\n            if (parentSlot.spriteInstance) {\n                // Check parent's visibility (subsprites inherit visibility from parent)\n                if (!parentSlot.visible) return [];\n\n                // Calculate which quad this slot represents\n                const quadIndex = slotIndex - parentIdx;\n\n                // Check if this quad exists in the parent sprite\n                if (quadIndex < parentSlot.spriteInstance.sprite[0].numSprites) {\n                    const pos = this._slotTo320(parentSlot);\n                    return parentSlot.spriteInstance.getHitboxes(pos.x, pos.y, quadIndex);\n                }\n                break;\n            }\n        }\n\n        return [];\n    }\n\n    // Returns hitboxes for ALL quads of a multi-part sprite (used for visualization)\n    getAllHitboxes(slotIndex) {\n        const slot = this.sprites[slotIndex];\n        if (!slot.visible || !slot.spriteInstance) return [];\n\n        const pos = this._slotTo320(slot);\n        return slot.spriteInstance.getHitboxes(pos.x, pos.y, -1); // -1 = all quads\n    }\n\n    // Check if a hitbox is fully off-screen (not visible at all)\n    // Screen dimensions: 320x200 (after coordinate transform)\n    isHitboxOffScreen(box) {\n        if (!box) return true;\n        // Check if hitbox is entirely outside the visible screen area\n        // Screen is 320 pixels wide (0-319) and 200 pixels tall (0-199) after transform\n        return (box.x + box.width <= 0 ||   // fully off left\n                box.x >= 320 ||              // fully off right\n                box.y + box.height <= 0 ||   // fully off top\n                box.y >= 200);               // fully off bottom\n    }\n\n    // === PIXEL-PERFECT COLLISION DETECTION (320×200 COORDINATES) ===\n    // With the new coordinate system, collision is much simpler:\n    // - All hitboxes are in 320×200 space\n    // - Sprite frames are stored as pixel arrays in 320×200 space\n    // - No scale factor conversions needed!\n\n    // Check pixel-perfect collision between two sprites\n    // Uses gmSprite.hasPixelAt() to check individual pixels in overlap region\n    checkPixelOverlap(gmSprite1, gmSprite2, box1, box2, frame1, frame2) {\n        // Calculate overlap region (all in 320×200 coordinates)\n        // Floor all values to ensure integer pixel coordinates\n        const left = Math.floor(Math.max(box1.x, box2.x));\n        const right = Math.floor(Math.min(box1.x + box1.width, box2.x + box2.width));\n        const top = Math.floor(Math.max(box1.y, box2.y));\n        const bottom = Math.floor(Math.min(box1.y + box1.height, box2.y + box2.height));\n\n        const overlapW = right - left;\n        const overlapH = bottom - top;\n\n        // No overlap\n        if (overlapW < 1 || overlapH < 1) {\n            return false;\n        }\n\n        // Check each pixel in the overlap region\n        for (let y = 0; y < overlapH; y++) {\n            for (let x = 0; x < overlapW; x++) {\n                const screenX = left + x;\n                const screenY = top + y;\n\n                // Convert to local coordinates within each sprite\n                const local1X = screenX - box1.x;\n                const local1Y = screenY - box1.y;\n                const local2X = screenX - box2.x;\n                const local2Y = screenY - box2.y;\n\n                // Check if both sprites have non-transparent pixels at this position\n                const hasPixel1 = gmSprite1.hasPixelAt(box1.quadIndex, frame1, local1X, local1Y);\n                const hasPixel2 = gmSprite2.hasPixelAt(box2.quadIndex, frame2, local2X, local2Y);\n\n                if (hasPixel1 && hasPixel2) {\n                    return true;\n                }\n            }\n        }\n\n        return false;\n    }\n\n    // Helper to find the parent sprite and gmSprite for a slot (handles subsprites)\n    _getSpriteInfo(slotIndex) {\n        const slot = this.sprites[slotIndex];\n\n        if (slot.spriteInstance) {\n            // This is a parent sprite slot - check visibility directly\n            if (!slot.visible) return null;\n            return { slot, gmSprite: slot.spriteInstance, parentSlot: slot };\n        }\n\n        // This might be a subsprite slot - find parent\n        // Subsprite visibility is inherited from parent, not checked on the slot itself\n        for (let parentIdx = slotIndex - 1; parentIdx >= 0; parentIdx--) {\n            const parentSlot = this.sprites[parentIdx];\n            if (parentSlot.spriteInstance) {\n                // Check parent's visibility instead\n                if (!parentSlot.visible) return null;\n\n                const quadIndex = slotIndex - parentIdx;\n                if (quadIndex < parentSlot.spriteInstance.sprite[0].numSprites) {\n                    return { slot, gmSprite: parentSlot.spriteInstance, parentSlot, quadIndex };\n                }\n                break;\n            }\n        }\n\n        return null;\n    }\n\n    checkSpriteCollision(sprite1Index, sprite2Index) {\n        const info1 = this._getSpriteInfo(sprite1Index);\n        const info2 = this._getSpriteInfo(sprite2Index);\n\n        if (!info1 || !info2) {\n            return false;\n        }\n\n        const { gmSprite: gmSprite1, parentSlot: parentSlot1 } = info1;\n        const { gmSprite: gmSprite2, parentSlot: parentSlot2 } = info2;\n\n        // Get hitboxes (already in 320×200 coordinates)\n        const boxes1 = this.getHitboxes(sprite1Index);\n        const boxes2 = this.getHitboxes(sprite2Index);\n\n        if (boxes1.length === 0 || boxes2.length === 0) {\n            return false;\n        }\n\n        // Check all combinations of hitboxes for overlap\n        for (const box1 of boxes1) {\n            if (this.isHitboxOffScreen(box1)) continue;\n\n            for (const box2 of boxes2) {\n                if (this.isHitboxOffScreen(box2)) continue;\n\n                // AABB check first (quick rejection)\n                const aabbOverlap = !(\n                    box1.x + box1.width < box2.x ||\n                    box2.x + box2.width < box1.x ||\n                    box1.y + box1.height < box2.y ||\n                    box2.y + box2.height < box1.y\n                );\n\n                if (aabbOverlap) {\n                    // AABB overlaps - do pixel-perfect check\n                    // All coordinates are now in 320×200 space - no conversions needed!\n                    const frame1 = parentSlot1.animFrame || 0;\n                    const frame2 = parentSlot2.animFrame || 0;\n\n                    const pixelOverlap = this.checkPixelOverlap(\n                        gmSprite1, gmSprite2, box1, box2, frame1, frame2\n                    );\n\n                    if (pixelOverlap) {\n                        return true;\n                    }\n                }\n            }\n        }\n\n        return false;\n    }\n\n    /**\n     * Check if sprite hits any other visible sprite (\"anyone\" collision)\n     * @param {number} spriteIndex - Index of sprite to check (0-7)\n     * @returns {boolean} True if sprite overlaps any other visible sprite\n     */\n    checkSpriteHitAnyone(spriteIndex) {\n        for (let i = 0; i < 8; i++) {\n            if (i === spriteIndex) continue; // Don't check against self\n            if (!this.sprites[i].visible) continue;\n            if (this.checkSpriteCollision(spriteIndex, i)) {\n                return true;\n            }\n        }\n        return false;\n    }\n\n    /**\n     * Check if sprite hits scene color slots 2 or 3 (pixel-perfect)\n     * @param {number} spriteIndex - Index of sprite to check (0-7)\n     * @returns {boolean} True if any non-transparent sprite pixel overlaps scene color 2 or 3\n     */\n    checkSpriteHitSceneColors(spriteIndex) {\n        const slot = this.sprites[spriteIndex];\n        if (!slot.visible || !slot.spriteInstance) return false;\n\n        const gmSprite = slot.spriteInstance;\n        const frameIndex = slot.animFrame || 0;\n\n        // Get sprite position in GM coordinates\n        const gmX = Math.floor(slot.x);\n        const gmY = Math.floor(slot.y);\n\n        // Get the current scene\n        const scene = this.scenes[this.activeScene];\n        if (!scene) return false;\n\n        // Get sprite dimensions accounting for doubling\n        const xDouble = gmSprite.sprite[0].xDouble ? 2 : 1;\n        const yDouble = gmSprite.sprite[0].yDouble ? 2 : 1;\n        const spriteWidthGm = 12 * xDouble;\n        const spriteHeightGm = 21 * yDouble;\n\n        // Check each quad of the sprite\n        for (let quad = 0; quad < gmSprite.sprite.length; quad++) {\n            const frame = gmSprite.getFrame(quad, frameIndex);\n            if (!frame) continue;\n\n            // Calculate quad's GM position\n            let quadGmX = gmX;\n            let quadGmY = gmY;\n            if (quad > 0) {\n                const spriteData = gmSprite.sprite[quad];\n                quadGmX += spriteData.xPosition;\n                quadGmY += spriteData.yPosition;\n            }\n\n            // Iterate over sprite pixels in GM coordinate space\n            for (let gmOffsetY = 0; gmOffsetY < spriteHeightGm; gmOffsetY++) {\n                const pixelGmY = (quadGmY + gmOffsetY) & 0xFF;\n                // Check if in visible Y range (50-249)\n                if (pixelGmY < 50 || pixelGmY >= 250) continue;\n\n                const sceneY = pixelGmY - 50;\n                const frameY = gmOffsetY;\n\n                for (let gmOffsetX = 0; gmOffsetX < spriteWidthGm; gmOffsetX++) {\n                    const pixelGmX = (quadGmX + gmOffsetX) & 0xFF;\n                    // Check if in visible X range (12-171)\n                    if (pixelGmX < 12 || pixelGmX >= 172) continue;\n\n                    // Convert to scene coordinates (160x200 fat pixels)\n                    const sceneX = pixelGmX - 12;\n\n                    // Check if this sprite pixel is non-transparent\n                    const frameX = gmOffsetX * 2; // Frame is in 320 space\n                    if (frameX >= frame.width || frameY >= frame.height) continue;\n\n                    const srcIdx = (frameY * frame.width + frameX) * 4;\n                    const alpha = frame.pixels[srcIdx + 3];\n                    if (alpha === 0) continue; // Transparent, skip\n\n                    // Check scene pixel's color index (0-3)\n                    const colorIndex = scene.getPixel(sceneX, sceneY);\n                    if (colorIndex === 2 || colorIndex === 3) {\n                        return true; // Hit color slot 2 or 3\n                    }\n                }\n            }\n        }\n\n        return false;\n    }\n\n    /**\n     * Render a score value to a scene's offscreen canvas.\n     * Called when score changes or when \"displays on scene\" is executed.\n     * @param {number} scoreIdx - Which score (0 or 1)\n     * @param {number} sceneIdx - Which scene to render to (0 or 1)\n     */\n    renderScoreToScene(scoreIdx, sceneIdx) {\n        const scene = this.scenes[sceneIdx];\n        if (!scene || !charset.loaded) {\n            return;\n        }\n\n        const scoreStr = this.score[scoreIdx].toString().padStart(6, '0');\n        const x = this.scoreCol[scoreIdx] * 8;\n        const y = this.scoreRow[scoreIdx] * 8;\n\n        // Draw directly to scene's pixel buffer using palette indices (0-3)\n        charset.drawStringToScene(scene, scoreStr, x, y, this.scoreFgColor[scoreIdx], this.scoreBgColor[scoreIdx]);\n    }\n\n    /**\n     * Update score display on assigned scene(s).\n     * Called whenever a score value changes.\n     * @param {number} scoreIdx - Which score changed (0 or 1)\n     */\n    updateScoreDisplay(scoreIdx) {\n        // Add/clear makes score visible and renders it\n        this.scoreVisible[scoreIdx] = true;\n\n        // Default to scene 0 if \"displays on scene\" was never called\n        const sceneTarget = this.scoreScene[scoreIdx];\n\n        if (sceneTarget === 0 || sceneTarget === 2) {\n            this.renderScoreToScene(scoreIdx, 0); // scene 1\n        }\n        if (sceneTarget === 1 || sceneTarget === 2) {\n            this.renderScoreToScene(scoreIdx, 1); // scene 2\n        }\n    }\n\n    updateSpritePositions() {\n        // Update sprite positions based on speed and direction\n        // Animation is handled by gmSprite itself\n        for (let i = 0; i < this.sprites.length; i++) {\n            const sprite = this.sprites[i];\n\n            if (!sprite.visible || sprite.speed === 0) continue;\n\n            // Convert GameMaker direction (0-255) to angle in radians\n            // 0 = up (270° in standard coords), 64 = right (0°), 128 = down (90°), 192 = left (180°)\n            // GameMaker: 0=up, increases clockwise\n            // We need: 0=up=-90°, 64=right=0°, 128=down=90°, 192=left=180°\n            const gmAngle = (sprite.direction / 256) * 360; // 0-360 degrees\n            const standardAngle = gmAngle - 90; // Convert GM angle (0=up) to standard (0=right)\n            const radians = (standardAngle * Math.PI) / 180;\n\n            // Calculate velocity based on verified speed formula\n            // C64 pixels aren't square (320x200 on 4:3 display), so X and Y have different rates\n            // Measured: X divisor ~46, Y divisor ~32. Tweaked for better feel.\n            const pixelsPerFrameX = sprite.speed / 46;\n            const pixelsPerFrameY = sprite.speed / 31.5;\n            const velocityX = Math.cos(radians) * pixelsPerFrameX;\n            const velocityY = Math.sin(radians) * pixelsPerFrameY;\n\n            // Update position\n            sprite.x += velocityX;\n            sprite.y += velocityY;\n\n            // Wrap around coordinate boundaries\n            // GameMaker coordinates go from 0-255 for both X and Y\n            if (sprite.x > 255) {\n                sprite.x = 0;\n            } else if (sprite.x < 0) {\n                sprite.x = 255;\n            }\n\n            if (sprite.y > 255) {\n                sprite.y = 0;\n            } else if (sprite.y < 0) {\n                sprite.y = 255;\n            }\n        }\n    }\n\n    // Advance sprite animation frames for all slots with animSpeed > 0.\n    // Peer of updateSpritePositions: both mutate runtime sprite state\n    // and both are callable independently of render() (so callers doing\n    // silent state advance — poster generation, headless smoke tests —\n    // can drive animation without touching the canvas).\n    //\n    // shouldAdvance mirrors what render's `advanceAnimation` toggle was:\n    // pass true on every other frame to reproduce the ~30fps animation\n    // cadence of the editor's run loop (see start()'s _loopAnimToggle).\n    advanceSpriteAnimations(shouldAdvance = true) {\n        if (!shouldAdvance) return;\n        for (const slot of this.sprites) {\n            if (!slot.visible || !slot.spriteInstance) continue;\n            const numFrames = slot.spriteInstance.getNumFrames();\n\n            // Defensive normalise — animFrame can drift if a sprite was\n            // reassigned to a shorter one after the last render.\n            if (typeof slot.animFrame !== 'number' || isNaN(slot.animFrame) ||\n                slot.animFrame < 0 || slot.animFrame >= numFrames) {\n                slot.animFrame = 0;\n            }\n\n            if (slot.animSpeed <= 0) continue;\n\n            // animateOnce: freeze on last frame, flag done, no advance.\n            if (slot.animateOnce && slot.animFrame >= numFrames - 1) {\n                slot.animateOnceDone = true;\n                continue;\n            }\n\n            // Clamp animSpeed 1-31 so framesToSkip stays positive.\n            const clampedSpeed = Math.max(1, Math.min(31, slot.animSpeed));\n            const framesToSkip = 32 - clampedSpeed;\n\n            if (typeof slot.skipCounter !== 'number' || isNaN(slot.skipCounter)) {\n                slot.skipCounter = framesToSkip;\n            }\n\n            if (slot.skipCounter <= 0) {\n                if (slot.animateOnce) {\n                    slot.animFrame = Math.min(slot.animFrame + 1, numFrames - 1);\n                } else {\n                    slot.animFrame = (slot.animFrame + 1) % numFrames;\n                }\n                slot.skipCounter = framesToSkip;\n            } else {\n                slot.skipCounter--;\n            }\n        }\n    }\n\n    // Convenience wrapper: one full frame of state advance + render.\n    // Equivalent to calling updateSpritePositions() + advanceSpriteAnimations()\n    // + renderPixels() in sequence. Handy for embedders driving a manual\n    // frame loop, or paused-preview modes.\n    //\n    // The main game loop (_loopTick) does NOT call this — it drives the\n    // three pieces separately so state can advance at virtual-frame rate\n    // (potentially multiple times per render) while pixels are painted\n    // once per browser tick.\n    //\n    // Callers who want state advance without a paint (or the reverse)\n    // should use the individual methods directly instead of a boolean\n    // parameter here.\n    updateAndRender() {\n        this.updateSpritePositions();\n        this.advanceSpriteAnimations(true);\n        this.renderPixels();\n    }\n\n    // Pure pixel work — no state mutation. Blits scene + sprites and calls\n    // present(). Called by _loopTick after it's already driven the virtual-\n    // frame state updates. External callers who want a paint without state\n    // advance can also use this directly.\n    renderPixels() {\n        if (!this.screenUpdateOn) return;\n\n        // === 320×200 NATIVE RESOLUTION RENDERING ===\n        // All rendering happens to screen.pixels (320×200 RGBA buffer).\n        // Scene fills the buffer, then sprites blit on top, then present() displays.\n\n        // Render scene background (or clear to black if no scene)\n        const activeSceneObj = this.scenes[this.activeScene];\n        if (activeSceneObj) {\n            // Scene blits to pixel buffer (fills entire screen, no transparency)\n            activeSceneObj.blitToBuffer(this.screen.pixels, c64Screen.WIDTH, c64Screen.HEIGHT);\n        } else {\n            // No scene - clear to black\n            this.screen.clear(0, 0, 0);\n        }\n\n        // Priority mask used by \"sprite under colors 2/3\" slots — built\n        // once per frame from the active scene and shared across all\n        // \"under\" sprites. The \"which indices are special\" choice lives\n        // here (C64 VIC hardware: colors 2 and 3 outrank sprites).\n        const underMask = activeSceneObj?.getUnderMask(UNDER_SKIP_INDICES) || null;\n\n        // Render sprites to pixel buffer\n        // Higher numbered sprites render on top, so loop from 7 to 0\n        // (sprite 0 drawn first = lowest z-index)\n        for (let i = this.sprites.length - 1; i >= 0; i--) {\n            const slot = this.sprites[i];\n            if (slot.visible && slot.spriteInstance) {\n                const gmSpriteObj = slot.spriteInstance;\n                if (gmSpriteObj) {\n                    // Ensure animFrame is valid and within bounds for THIS sprite\n                    const numFrames = gmSpriteObj.getNumFrames();\n                    if (typeof slot.animFrame !== 'number' || isNaN(slot.animFrame) ||\n                        slot.animFrame < 0 || slot.animFrame >= numFrames) {\n                        slot.animFrame = 0;\n                    }\n\n                    // Blit sprite to screen's pixel buffer\n                    // Pass GM coordinates - blitToBuffer handles coordinate conversion and wrapping\n                    const mask = slot.overUnder === 1 ? underMask : null;\n                    gmSpriteObj.blitToBuffer(this.screen.pixels, c64Screen.WIDTH, c64Screen.HEIGHT, slot.x, slot.y, slot.animFrame, slot.skipQuads, mask);\n                }\n            }\n        }\n\n        // Present the composited frame to the canvas\n        this.screen.present();\n\n        // Draw collision hitboxes if enabled (drawn after present, directly to canvas)\n        if (this.config.showHitboxes) {\n            this.drawHitboxes();\n        }\n    }\n\n    drawHitboxes() {\n        // Hitboxes are in 320×200 coordinates, same as canvas\n        // No scaling needed - draw directly to canvas after present()\n        const ctx = this.screen.ctx;\n\n        for (let i = 0; i < this.sprites.length; i++) {\n            const slot = this.sprites[i];\n            // Skip reserved subsprite slots (they don't have their own hitbox)\n            if (slot.isSubsprite) continue;\n\n            // Use getAllHitboxes for visualization (shows all quads of multi-part sprites)\n            const hitboxes = this.getAllHitboxes(i);\n            if (hitboxes.length === 0) continue;\n\n            // Draw all hitboxes for this sprite (main + subsprites)\n            for (const hitbox of hitboxes) {\n                // Draw rectangle outline (coordinates already in 320×200 space)\n                ctx.strokeStyle = 'rgba(255, 0, 255, 0.8)';  // Magenta\n                ctx.lineWidth = 1;\n                ctx.strokeRect(hitbox.x, hitbox.y, hitbox.width, hitbox.height);\n\n                // Draw sprite slot number\n                ctx.fillStyle = 'rgba(255, 0, 255, 1)';\n                ctx.font = '10px monospace';\n                const slotNum = i + 1 + hitbox.quadIndex;\n                ctx.fillText(`${slotNum}`, hitbox.x + 1, hitbox.y + 9);\n            }\n        }\n    }\n}\n\n// Make available globally for browser and Node.js testing\nif (typeof globalThis !== 'undefined') {\n    globalThis.gmVM = gmVM;\n}\n</script>\n<script>// gmAudioIndicator — speaker-icon button that shows + toggles audio state.\n//\n// One control, two visual states (muted / unmuted), reused across every\n// surface that renders a game: the editor's play overlay, the eventual\n// headless game export, and any future embed iframe. Centralising it\n// here means audio UX stays consistent — and a single click on the icon\n// is both the user-gesture handler the browser autoplay policy requires\n// AND the unmute toggle the user expects.\n//\n// \"Muted\" is the *effective* state: the icon shows a strike-through\n// speaker when the user has explicitly muted OR when the AudioContext is\n// browser-suspended. The user doesn't need to know the difference; one\n// click resolves both.\n//\n// Wiring:\n//\n//   const indicator = new GMAudioIndicator(parentEl);\n//   indicator.bind({\n//       getMuted:        () => audioMuted,\n//       setMuted:        (m) => { audioMuted = m; vm.setConfig({audioMuted: m}); },\n//       getAudioContext: () => audioContext,\n//       onUnlock:        () => { /* restart song, etc. */ }\n//   });\n//   // call indicator.refresh() any time external state changes.\n\nclass GMAudioIndicator {\n    constructor(parent) {\n        const btn = document.createElement('button');\n        btn.className = 'gm-audio-indicator';\n        btn.type = 'button';\n        btn.title = 'Toggle sound';\n        btn.setAttribute('aria-label', 'Toggle sound');\n        parent.appendChild(btn);\n\n        this.btn = btn;\n        this.binding = null;\n        this._renderedMuted = null; // last drawn state, for skip-if-unchanged\n\n        btn.addEventListener('click', () => this._onClick());\n\n        // Initial render — assume muted until bound and told otherwise.\n        this._render(true);\n    }\n\n    bind({ getMuted, setMuted, getAudioContext, onUnlock }) {\n        this.binding = { getMuted, setMuted, getAudioContext, onUnlock };\n        this.refresh();\n    }\n\n    refresh() {\n        // Lazy-attach the statechange listener the first time we see a\n        // real AudioContext. Bind may have happened before the host\n        // created the context (the editor lazy-inits audio on first run),\n        // so we can't rely on context existing at bind time.\n        if (this.binding && !this._statechangeAttached) {\n            const ctx = this.binding.getAudioContext?.();\n            if (ctx && typeof ctx.addEventListener === 'function') {\n                ctx.addEventListener('statechange', () => this.refresh());\n                this._statechangeAttached = true;\n            }\n        }\n        this._render(this._isEffectivelyMuted());\n    }\n\n    _isEffectivelyMuted() {\n        if (!this.binding) return true;\n        if (this.binding.getMuted()) return true;\n        const ctx = this.binding.getAudioContext?.();\n        if (ctx && ctx.state === 'suspended') return true;\n        return false;\n    }\n\n    _onClick() {\n        if (!this.binding) return;\n        const wasMuted = this._isEffectivelyMuted();\n        if (wasMuted) {\n            // Unmute path: clear user mute, resume context (if suspended —\n            // and this click is the user gesture that lets resume() actually\n            // work), then notify host so it can restart any song that lost\n            // its scheduling window during the suspension.\n            this.binding.setMuted(false);\n            const ctx = this.binding.getAudioContext?.();\n            if (ctx && ctx.state === 'suspended') {\n                ctx.resume().then(() => {\n                    if (this.binding.onUnlock) this.binding.onUnlock();\n                    this.refresh();\n                });\n            }\n        } else {\n            this.binding.setMuted(true);\n        }\n        this.refresh();\n    }\n\n    _render(muted) {\n        if (this._renderedMuted === muted) return;\n        this._renderedMuted = muted;\n        this.btn.classList.toggle('muted', muted);\n        this.btn.innerHTML = this._iconHTML(muted);\n    }\n\n    _iconHTML(muted) {\n        // Simple inline SVG — speaker cone with optional sound-waves\n        // (unmuted) or a strike-through (muted). currentColor lets CSS\n        // recolour the whole icon.\n        const speaker = '<path d=\"M3 9v6h4l5 4V5L7 9H3z\" fill=\"currentColor\"/>';\n        const waves   = '<path d=\"M14 8a4 4 0 0 1 0 8M17 5a8 8 0 0 1 0 14\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\"/>';\n        const slash   = '<line x1=\"3\" y1=\"3\" x2=\"21\" y2=\"21\" stroke=\"currentColor\" stroke-width=\"2.5\" stroke-linecap=\"round\"/>';\n        const body = muted ? speaker + slash : speaker + waves;\n        return `<svg viewBox=\"0 0 24 24\" xmlns=\"http://www.w3.org/2000/svg\" aria-hidden=\"true\">${body}</svg>`;\n    }\n}\n\n// Make available globally for browser <script> loads and Node.js ESM imports.\nif (typeof globalThis !== 'undefined') {\n    globalThis.GMAudioIndicator = GMAudioIndicator;\n}\n</script>\n<script>// Poster preview generation — shared between editor.html and play.html.\n//\n// A \"poster\" is the frame you see behind the play-button overlay: the game\n// simulated for a few seconds so the visitor sees something more interesting\n// than a black canvas. It runs against a throwaway VM + fresh mediaStore so\n// the real run (started when the user clicks play) isn't perturbed.\n//\n// Callers own their own screen instance and pass it in. Both hosts want the\n// poster rendered on the same canvas the real VM will eventually use, so\n// there's no benefit to owning the screen here.\n\nglobalThis.GMPoster = {\n    // Parse `poster_seconds` from URL params.\n    //   absent / non-numeric / negative → default 2s\n    //   0                                → caller should skip poster entirely\n    //   > 10                             → capped at 10s (protects against runaway URLs)\n    //   decimals                         → rounded to 0.01s\n    getPosterSeconds(params) {\n        const raw = params.get('poster_seconds');\n        if (raw === null) return 2;\n        const parsed = parseFloat(raw);\n        if (!isFinite(parsed) || parsed < 0) return 2;\n        return Math.min(Math.round(parsed * 100) / 100, 10);\n    },\n\n    // Render a preview frame to `screen` by running a temp VM for\n    // `posterSeconds` of simulated wallclock. `fileData` is the raw PRG\n    // bytes — parsed fresh so we don't share mediaStore with the real run.\n    //\n    // Date.now is mocked to advance one frame per simulated frame so\n    // `pause X.X` opcodes resolve without actually blocking. audioMuted\n    // silences song-start opcodes even if an AudioContext already exists\n    // from a previous run (relevant to editor.html; play.html's context\n    // doesn't exist yet at poster time).\n    async generatePoster({ screen, fileData, posterSeconds }) {\n        if (!fileData || posterSeconds === 0) return;\n\n        const realDateNow = Date.now.bind(Date);\n        let simulatedNow = realDateNow();\n        Date.now = () => simulatedNow;\n\n        try {\n            const programData = parseProgramData(fileData);\n            const ast = buildAST(programData);\n            const vm = new gmVM(screen);\n            vm.loadProgram(ast, fileData, { audioMuted: true });\n            vm.running = true;\n\n            const totalFrames = Math.max(1, Math.round(posterSeconds * 60));\n            const opsPerFrame = 50;\n            const frameMs = 1000 / 60;\n            // Mirror the real run loop: animation advances every other\n            // frame so sprites land at ~30fps like on real hardware.\n            let animToggle = false;\n            for (let f = 0; f < totalFrames && vm.running; f++) {\n                for (let i = 0; i < opsPerFrame && vm.running; i++) {\n                    vm.step();\n                }\n                vm.updateSpritePositions();\n                animToggle = !animToggle;\n                vm.advanceSpriteAnimations(animToggle);\n                simulatedNow += frameMs;\n            }\n            // Only the final frame matters — intermediate paints inside a\n            // sync loop never composite anyway. renderPixels() paints the\n            // current state without touching sprite positions or animation\n            // (both already advanced in the loop above).\n            vm.renderPixels();\n        } catch (e) {\n            console.warn('poster generation failed:', e.message);\n        } finally {\n            Date.now = realDateNow;\n        }\n    }\n};\n</script>\n<script>// Shared player chrome behaviors — used by play.html, editor.html's game\n// overlay, and the standalone Export Game bundle. Each host owns its own\n// DOM structure (they only differ around it — editor.html has additional\n// dev controls in the settings popup, play.html doesn't need a stop\n// button, etc.), but the icon set, joystick presets, input listeners,\n// pause-icon swap, and settings persistence are all identical, so they\n// live here.\n\nglobalThis.GMPlayerChrome = (function () {\n\n    // ---------- Icons ---------------------------------------------------\n\n    // SVG strings inlined into buttons via .innerHTML. Same viewBox,\n    // stroke width, and color tokens so all four buttons visually match.\n    // `currentColor` lets each host color the icons via CSS.\n    const ICONS = {\n        // Play: rounded triangle. Larger stroke than the others because\n        // it's the hero button in the play overlay.\n        play:\n            '<svg viewBox=\"0 0 24 24\" xmlns=\"http://www.w3.org/2000/svg\" aria-hidden=\"true\">' +\n            '<path d=\"M7 5 L19 12 L7 19 Z\" fill=\"currentColor\" stroke=\"currentColor\" ' +\n            'stroke-width=\"3\" stroke-linejoin=\"round\" stroke-linecap=\"round\"/>' +\n            '</svg>',\n\n        // Pause: two rounded bars.\n        pause:\n            '<svg viewBox=\"0 0 24 24\" xmlns=\"http://www.w3.org/2000/svg\" aria-hidden=\"true\">' +\n            '<rect x=\"6\" y=\"5\" width=\"4\" height=\"14\" rx=\"1\" fill=\"currentColor\"/>' +\n            '<rect x=\"14\" y=\"5\" width=\"4\" height=\"14\" rx=\"1\" fill=\"currentColor\"/>' +\n            '</svg>',\n\n        // Resume: same triangle as play, but with a lighter stroke — used\n        // on the pause button when the VM is currently paused.\n        resume:\n            '<svg viewBox=\"0 0 24 24\" xmlns=\"http://www.w3.org/2000/svg\" aria-hidden=\"true\">' +\n            '<path d=\"M7 5 L19 12 L7 19 Z\" fill=\"currentColor\" stroke=\"currentColor\" ' +\n            'stroke-width=\"2\" stroke-linejoin=\"round\" stroke-linecap=\"round\"/>' +\n            '</svg>',\n\n        // Stop: single filled rounded square.\n        stop:\n            '<svg viewBox=\"0 0 24 24\" xmlns=\"http://www.w3.org/2000/svg\" aria-hidden=\"true\">' +\n            '<rect x=\"6\" y=\"6\" width=\"12\" height=\"12\" rx=\"1\" fill=\"currentColor\"/>' +\n            '</svg>',\n\n        // Hamburger: three rounded horizontal bars.\n        hamburger:\n            '<svg viewBox=\"0 0 24 24\" xmlns=\"http://www.w3.org/2000/svg\" aria-hidden=\"true\">' +\n            '<rect x=\"4\" y=\"6\" width=\"16\" height=\"2\" rx=\"1\" fill=\"currentColor\"/>' +\n            '<rect x=\"4\" y=\"11\" width=\"16\" height=\"2\" rx=\"1\" fill=\"currentColor\"/>' +\n            '<rect x=\"4\" y=\"16\" width=\"16\" height=\"2\" rx=\"1\" fill=\"currentColor\"/>' +\n            '</svg>'\n    };\n\n    // Swap a pause button between \"showing pause\" (VM running) and\n    // \"showing resume\" (VM paused). Also updates aria-label.\n    function setPauseIcon(btn, paused) {\n        if (!btn) return;\n        btn.innerHTML = paused ? ICONS.resume : ICONS.pause;\n        btn.setAttribute('aria-label', paused ? 'Resume' : 'Pause');\n    }\n\n    // ---------- Joystick presets ---------------------------------------\n\n    // Each preset maps `event.key` values to a *joystick action*:\n    // 'up'/'down'/'left'/'right' set the corresponding joystick direction;\n    // 'fire' sets the top-level button state (buttonN, not joystickN.fire —\n    // that's the field the runtime actually reads).\n    //\n    // Presets are joystick-agnostic here. The setup wires each preset to a\n    // specific joystick number at attach time, so the same 'cursors' preset\n    // can drive joystick 1 in one game and joystick 2 in another. Games\n    // that overlap keys across joysticks just fire both — that's the\n    // user's choice to make when they pair presets.\n    //\n    // 'cursors' accepts both Enter and Meta as fire so it works for\n    // finger positions that expect either. 'none' is the \"this joystick\n    // is unused\" preset.\n    const PRESETS = {\n        cursors: {\n            ArrowUp: 'up', ArrowDown: 'down', ArrowLeft: 'left', ArrowRight: 'right',\n            Enter: 'fire', Meta: 'fire'\n        },\n        esdf: {\n            e: 'up', E: 'up', d: 'down', D: 'down',\n            s: 'left', S: 'left', f: 'right', F: 'right',\n            ' ': 'fire'\n        },\n        wasd: {\n            w: 'up', W: 'up', s: 'down', S: 'down',\n            a: 'left', A: 'left', d: 'right', D: 'right',\n            ' ': 'fire'\n        },\n        ijkl: {\n            i: 'up', I: 'up', k: 'down', K: 'down',\n            j: 'left', J: 'left', l: 'right', L: 'right',\n            Enter: 'fire'\n        },\n        none: {}\n    };\n\n    // Human-readable labels for populating the settings dropdowns.\n    // Order here becomes the display order in the UI.\n    const PRESET_LABELS = [\n        ['cursors', 'Arrow keys + Enter'],\n        ['esdf', 'ESDF + Space'],\n        ['wasd', 'WASD + Space'],\n        ['ijkl', 'IJKL + Enter'],\n        ['none', '(off)']\n    ];\n\n    // Attach keydown/keyup listeners to `window`. On each event, look up\n    // both joysticks' presets and mutate `inputState` accordingly.\n    //\n    // `getPresets()` returns { joy1: 'cursors', joy2: 'esdf' } — read at\n    // event time so preset changes take effect immediately without\n    // reattaching. `isEnabled()` gates event handling (games with no VM\n    // running or a paused game shouldn't consume presses).\n    //\n    // Returns a `detach()` function for cleanup — useful for the editor\n    // where the overlay comes and goes.\n    function setupInputListeners({ inputState, getPresets, isEnabled }) {\n        function applyKey(key, active, e) {\n            const { joy1, joy2 } = getPresets();\n            let consumed = false;\n            const m1 = PRESETS[joy1] || {};\n            const m2 = PRESETS[joy2] || {};\n\n            const act1 = m1[key];\n            if (act1) {\n                if (act1 === 'fire') inputState.button1 = active;\n                else inputState.joystick1[act1] = active;\n                consumed = true;\n            }\n            const act2 = m2[key];\n            if (act2) {\n                if (act2 === 'fire') inputState.button2 = active;\n                else inputState.joystick2[act2] = active;\n                consumed = true;\n            }\n            if (consumed && e) e.preventDefault();\n        }\n\n        function onDown(e) { if (isEnabled()) applyKey(e.key, true, e); }\n        function onUp(e) { if (isEnabled()) applyKey(e.key, false, e); }\n\n        // Capture phase so we run before any bubble-phase listeners that\n        // might call stopImmediatePropagation (e.g., the editor's blocker\n        // that stops editor shortcuts from firing during gameplay). We\n        // preventDefault on matched keys but don't stop propagation\n        // ourselves — the host's other handlers still get to run.\n        window.addEventListener('keydown', onDown, true);\n        window.addEventListener('keyup', onUp, true);\n        return () => {\n            window.removeEventListener('keydown', onDown, true);\n            window.removeEventListener('keyup', onUp, true);\n        };\n    }\n\n    // ---------- Settings persistence -----------------------------------\n\n    // Each host uses a different localStorage key so a user's preset\n    // choice in the editor doesn't leak into play.html and vice versa —\n    // people may want different mappings for the two contexts.\n    function loadInputSettings(storageKey, defaults) {\n        try {\n            const raw = localStorage.getItem(storageKey);\n            if (!raw) return { ...defaults };\n            const parsed = JSON.parse(raw);\n            return { ...defaults, ...parsed };\n        } catch (e) {\n            return { ...defaults };\n        }\n    }\n\n    function saveInputSettings(storageKey, settings) {\n        try {\n            localStorage.setItem(storageKey, JSON.stringify(settings));\n        } catch (e) {\n            // Quota exceeded or private mode — settings just don't stick.\n        }\n    }\n\n    // Default choice used by every host: cursors for joystick 1, ESDF for\n    // joystick 2. Matches the hardcoded mappings that used to live in each\n    // host, so existing muscle memory carries over.\n    const DEFAULT_INPUT_SETTINGS = { joy1: 'cursors', joy2: 'esdf' };\n\n    // ---------- Public API ---------------------------------------------\n\n    return {\n        ICONS,\n        PRESETS,\n        PRESET_LABELS,\n        DEFAULT_INPUT_SETTINGS,\n        setPauseIcon,\n        setupInputListeners,\n        loadInputSettings,\n        saveInputSettings\n    };\n})();\n</script>\n<script>// Shared disk-picker overlay used by play.html and every editor. Two states:\n//   - drop-zone: \"Drop a .d64 here\" GameMaker-button, with a hidden file\n//                input for click-to-choose fallback\n//   - program-picker: list of files on the loaded disk, filtered to the\n//                host's extension (PRG / SPR / PIC / SND / SNG)\n//\n// Callers mount once at page init, then either:\n//   - call showProgramPicker() when they already have a disk (URL-driven\n//     load with ?disk= but no ?file=)\n//   - enable windowDropEnabled to auto-show the drop-zone on drag-and-\n//     drop of a .d64 anywhere in the window\n//\n// Post-pick, callers get the file name + bytes + parsed D64 via\n// onPickFile(name, bytes, disk, diskLabel). What they do with it varies\n// by host (editor loads into the program listing, sprite-maker into the\n// sprite canvas, play.html into the poster + play flow, etc.).\n//\n// Styling: GameMaker quit-menu aesthetic (dark gray screen, gray3-blue\n// raised buttons). CSS injects once per page on first mount and lives\n// under `.gmdp-*` class prefixes so it can't collide with host styles.\n\nglobalThis.GMDiskPicker = (function () {\n\n    // The `--gameborder-h, 100vh` fallback lets the same rule work in\n    // play.html (where --gameborder-h is defined and reflects the game\n    // border's real height) AND in editors where the overlay covers the\n    // viewport (no --gameborder-h; fall back to raw viewport height).\n    const CSS = `\n@font-face {\n    font-family: C64;\n    src: url(css/fonts/C64_Pro_Mono_Narrow8.woff2);\n}\n\n.gmdp-overlay {\n    display: none;\n    position: absolute;\n    inset: 0;\n    padding: max(0px, min(48px, calc((var(--gameborder-h, 100vh) - 400px) / 2)));\n    box-sizing: border-box;\n    align-items: center;\n    justify-content: center;\n    z-index: 1000;\n    background: rgb(0, 0, 0);\n}\n.gmdp-overlay.active { display: flex; }\n\n.gmdp-content {\n    height: 100%;\n    aspect-ratio: 6 / 5;\n    min-height: 400px;\n    box-sizing: border-box;\n    background: rgb(98, 98, 98);         /* c64-gray1 */\n    font-family: C64, monospace;\n    padding: 40px;\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    overflow: hidden;\n    color: rgb(205, 205, 205);\n}\n\n.gmdp-content code { font-family: inherit; font-size: inherit; }\n\n.gmdp-content > * {\n    width: 100%;\n    max-width: 380px;\n    text-align: center;\n}\n\n.gmdp-heading {\n    font-size: 12px;\n    margin: 0 0 14px 0;\n    font-weight: normal;\n    color: rgb(205, 205, 205);\n}\n.gmdp-disk-name {\n    font-size: 11px;\n    margin: 0 0 12px 0;\n    color: rgb(205, 205, 205);\n}\n\n/* GameMaker raised button: gray3 fill, blue text, black 3D bevel via\n   thicker bottom/right borders. Same as css/gm-ui.css's global button. */\n.gmdp-drop-target {\n    display: block;\n    background: rgb(205, 205, 205);      /* c64-gray3 */\n    color: rgb(25, 73, 180);             /* c64-blue */\n    border: 3px solid black;\n    border-bottom: 6px solid black;\n    border-right: 6px solid black;\n    padding: 16px 24px;\n    cursor: pointer;\n    transition: background 0.1s;\n}\n.gmdp-drop-target:hover,\n.gmdp-drop-target.gmdp-drag-over {\n    background: rgb(255, 255, 255);      /* c64-white */\n}\n.gmdp-drop-hint {\n    font-size: 13px;\n    margin-bottom: 6px;\n}\n.gmdp-drop-sub {\n    font-size: 11px;\n    opacity: 0.75;\n}\n.gmdp-drop-input { display: none; }\n\n/* Program list — same raised-panel bevel, quit-menu-style link rows.\n   max-height caps the panel so it always fits inside the 400px-min\n   mini-screen (with room for the heading + disk-name above); long\n   file lists scroll internally rather than pushing the panel out of\n   the mini-screen and getting clipped. */\n.gmdp-list {\n    list-style: none;\n    margin: 0;\n    padding: 12px 20px;\n    max-height: 220px;\n    overflow-y: auto;\n    background: rgb(205, 205, 205);\n    border: 3px solid black;\n    border-bottom: 6px solid black;\n    border-right: 6px solid black;\n    text-align: left;\n    box-sizing: border-box;\n}\n.gmdp-list li {\n    padding: 3px 8px;\n    cursor: pointer;\n    font-size: 12px;\n    color: rgb(25, 73, 180);\n    transition: color 0.1s;\n}\n.gmdp-list li:hover {\n    color: rgb(169, 71, 100);            /* c64-red */\n}\n\n.gmdp-error {\n    display: none;\n    font-size: 11px;\n    margin-top: 12px;\n    color: rgb(169, 71, 100);\n}\n`;\n\n    let cssInjected = false;\n    function injectCSS() {\n        if (cssInjected) return;\n        const style = document.createElement('style');\n        style.textContent = CSS;\n        document.head.appendChild(style);\n        cssInjected = true;\n    }\n\n    // Detect that a drag actually carries files (not, e.g., text or an\n    // in-page HTML5 drag from a list). Some browsers redact file metadata\n    // during drag for security, so this is a \"yes, files are involved\"\n    // check rather than a `.d64`-specific one — the extension is checked\n    // only on drop where we can read `file.name`.\n    function dragCarriesFile(dt) {\n        if (!dt) return false;\n        const types = dt.types;\n        // types is a DOMStringList; iterate with a loop that works both\n        // for old and new browsers.\n        for (let i = 0; i < types.length; i++) {\n            if (types[i] === 'Files') return true;\n        }\n        return false;\n    }\n\n    function mount(hostEl, options) {\n        const { extension, onPickFile, windowDropEnabled, disk } = options;\n        // Optional: when a drop yields 2+ matches, call this instead of\n        // showing the module's own overlay picker. Editors use it to\n        // hand off to their existing file-popup UI (which already has\n        // previews for sprites/scenes, etc.) so users only ever see one\n        // picker. If not provided, the module's overlay picker is used.\n        const customPicker = options.showPicker;\n        injectCSS();\n\n        const overlay = document.createElement('div');\n        overlay.className = 'gmdp-overlay';\n        overlay.innerHTML = `\n            <div class=\"gmdp-content\">\n                <div class=\"gmdp-drop-section\">\n                    <label class=\"gmdp-drop-target\">\n                        <div class=\"gmdp-drop-hint\">Drop a <code>.d64</code> here</div>\n                        <div class=\"gmdp-drop-sub\">or click to choose a file</div>\n                        <input type=\"file\" class=\"gmdp-drop-input\" accept=\".d64\">\n                    </label>\n                    <div class=\"gmdp-error\"></div>\n                </div>\n                <div class=\"gmdp-pick-section\" style=\"display: none;\">\n                    <h2 class=\"gmdp-heading\">Choose a program</h2>\n                    <p class=\"gmdp-disk-name\"></p>\n                    <ul class=\"gmdp-list\"></ul>\n                </div>\n            </div>\n        `;\n        hostEl.appendChild(overlay);\n\n        const dropTarget  = overlay.querySelector('.gmdp-drop-target');\n        const dropInput   = overlay.querySelector('.gmdp-drop-input');\n        const dropSection = overlay.querySelector('.gmdp-drop-section');\n        const pickSection = overlay.querySelector('.gmdp-pick-section');\n        const errBox      = overlay.querySelector('.gmdp-error');\n        const diskLabelEl = overlay.querySelector('.gmdp-disk-name');\n        const listEl      = overlay.querySelector('.gmdp-list');\n\n        function isVisible() { return overlay.classList.contains('active'); }\n        function hide() { overlay.classList.remove('active'); }\n\n        function showDropZone() {\n            errBox.style.display = 'none';\n            dropSection.style.display = '';\n            pickSection.style.display = 'none';\n            overlay.classList.add('active');\n        }\n\n        function showProgramPicker(disk, files, diskLabel) {\n            diskLabelEl.textContent = diskLabel || '';\n            listEl.innerHTML = '';\n            for (const name of files) {\n                const li = document.createElement('li');\n                li.textContent = name;\n                li.addEventListener('click', () => {\n                    const bytes = disk.readFile(name);\n                    if (!bytes) return;\n                    hide();\n                    onPickFile(name, bytes, disk, diskLabel);\n                });\n                listEl.appendChild(li);\n            }\n            dropSection.style.display = 'none';\n            pickSection.style.display = '';\n            overlay.classList.add('active');\n        }\n\n        function showError(msg) {\n            errBox.textContent = msg;\n            errBox.style.display = '';\n            dropSection.style.display = '';\n            pickSection.style.display = 'none';\n            overlay.classList.add('active');\n        }\n\n        // Parse a File as a .d64, then run the same auto-load/pick logic\n        // as the URL flow: 0 matches → error; 1 match → auto-pick;\n        // multiple → show the program picker.\n        //\n        // If a GMDisk was passed to mount(), the dropped bytes get\n        // promoted into the shared localStorage pool AND selected as the\n        // current disk — so subsequent \"file\" button clicks see the\n        // just-dropped disk, saves land in the right place, and other\n        // editors see it too. addToPool dedupes by SHA-256 so re-dropping\n        // the same disk is a no-op that just re-selects the existing\n        // pool entry.\n        async function handleFile(file) {\n            errBox.style.display = 'none';\n            try {\n                const bytes = new Uint8Array(await file.arrayBuffer());\n                const parsed = new D64(bytes);\n                if (disk) {\n                    try {\n                        const id = await GMDisk.addToPool(bytes, file.name);\n                        disk.selectDisk(id);\n                    } catch (e) {\n                        // Pool insert can fail (quota, private mode). Fall\n                        // through with the in-memory disk — the current\n                        // pick still works, just doesn't persist.\n                        console.warn('GMDiskPicker: pool insert failed:', e.message);\n                    }\n                }\n                // The host's `disk` object now points at the pool entry\n                // (via selectDisk); fall back to the in-memory `parsed`\n                // when no host disk was provided.\n                const activeD64 = disk?.disk || parsed;\n                // gmParser needs loadFileByName to resolve multi-part\n                // sprite references etc. Point it at this disk.\n                globalThis.loadFileByName = (name) => {\n                    try { return activeD64.readFile(name); } catch (e) { return null; }\n                };\n                const matches = GMTools.listFilesByExtension(activeD64, extension);\n                if (matches.length === 0) {\n                    showError(`no ${extension.toLowerCase()} files on disk`);\n                    return;\n                }\n                if (matches.length === 1) {\n                    const name = matches[0];\n                    const data = activeD64.readFile(name);\n                    hide();\n                    onPickFile(name, data, activeD64, file.name);\n                    return;\n                }\n                // 2+ matches: hand off to the caller's custom picker if\n                // one was provided (editors use their existing file-popup\n                // UI); otherwise fall back to the module's overlay picker.\n                if (customPicker) {\n                    hide();\n                    customPicker(matches, file.name);\n                } else {\n                    showProgramPicker(activeD64, matches, file.name);\n                }\n            } catch (e) {\n                showError(\"that doesn't look like a valid .d64\");\n            }\n        }\n\n        // Drop handlers on the drop-target label — used when the user\n        // drops directly onto the visible button.\n        dropInput.addEventListener('change', () => {\n            if (dropInput.files && dropInput.files[0]) handleFile(dropInput.files[0]);\n        });\n        dropTarget.addEventListener('dragover', (e) => {\n            e.preventDefault();\n            dropTarget.classList.add('gmdp-drag-over');\n        });\n        dropTarget.addEventListener('dragleave', () => {\n            dropTarget.classList.remove('gmdp-drag-over');\n        });\n        dropTarget.addEventListener('drop', (e) => {\n            e.preventDefault();\n            dropTarget.classList.remove('gmdp-drag-over');\n            const file = e.dataTransfer?.files?.[0];\n            if (file) handleFile(file);\n        });\n\n        // Window-level drop: any file dragged into the window shows the\n        // overlay. If the overlay was already visible when the drag\n        // started (e.g., URL missing ?file=), leave it visible on\n        // dragleave — otherwise auto-hide when the drag exits the window.\n        // Counter-based nesting handles dragenter/leave fluctuations as\n        // the cursor crosses inner elements.\n        if (windowDropEnabled) {\n            let dragCounter = 0;\n            let wasVisibleBeforeDrag = false;\n\n            window.addEventListener('dragenter', (e) => {\n                if (!dragCarriesFile(e.dataTransfer)) return;\n                if (dragCounter === 0) {\n                    wasVisibleBeforeDrag = isVisible();\n                    showDropZone();\n                }\n                dragCounter++;\n                e.preventDefault();\n            });\n            window.addEventListener('dragleave', (e) => {\n                if (!dragCarriesFile(e.dataTransfer)) return;\n                dragCounter--;\n                if (dragCounter <= 0) {\n                    dragCounter = 0;\n                    if (!wasVisibleBeforeDrag) hide();\n                }\n            });\n            window.addEventListener('dragover', (e) => {\n                // Preventing default here is what lets `drop` fire.\n                if (dragCarriesFile(e.dataTransfer)) e.preventDefault();\n            });\n            window.addEventListener('drop', (e) => {\n                dragCounter = 0;\n                if (!dragCarriesFile(e.dataTransfer)) return;\n                e.preventDefault();\n                const file = e.dataTransfer.files?.[0];\n                if (file) handleFile(file);\n                else if (!wasVisibleBeforeDrag) hide();\n            });\n        }\n\n        return { showDropZone, showProgramPicker, showError, hide, isVisible };\n    }\n\n    return { mount };\n})();\n</script>\n<script>// gmTouchControls.js — Virtual joystick + fire button overlay for mobile play.\n//\n// Mounts translucent controls onto the game canvas that write directly to the\n// global inputState the VM reads each frame. Both play.html and editor.html\n// (in play mode) use it.\n//\n// Usage:\n//     const controls = GMTouchControls.mount(hostEl, { inputState });\n//     // ... later ...\n//     controls.unmount();\n//\n// Options:\n//   inputState  — the object with joystick1/button1 fields (defaults to globalThis.inputState)\n//   port        — which joystick port to write to (1 or 2, default 1)\n//\n// Device detection: shown only on touch-primary devices with a small viewport\n// (phone-sized). Tablets and desktops keep the keyboard-driven UX. Use\n// GMTouchControls.deviceMode() for the classification helper.\n\nconst GMTouchControls = {\n    // === DEVICE CLASSIFICATION ===\n    // \"phone\"   — small touch device (< 900px wide, coarse pointer). Full\n    //             mobile treatment: hide chrome, show virtual controls.\n    // \"tablet\"  — large touch device. Show virtual controls but keep the\n    //             desktop chrome; user has room for both.\n    // \"desktop\" — non-touch or fine-pointer. No virtual controls at all;\n    //             keyboard driving.\n    deviceMode() {\n        const coarse = matchMedia('(pointer: coarse)').matches;\n        const hasTouch = 'ontouchstart' in window || navigator.maxTouchPoints > 0;\n        if (!coarse && !hasTouch) return 'desktop';\n        const small = window.innerWidth < 900;\n        return small ? 'phone' : 'tablet';\n    },\n\n    // Simple boolean for \"should we show virtual controls?\" — true for both\n    // phones and tablets; only desktops are excluded.\n    shouldShowControls() {\n        return this.deviceMode() !== 'desktop';\n    },\n\n    // Simple boolean for \"should we hide the desktop chrome?\" — phones only.\n    // Tablets keep the chrome because they have screen real-estate for it.\n    isPhoneLayout() {\n        return this.deviceMode() === 'phone';\n    },\n\n    // === MOUNT ===\n    mount(hostEl, { inputState = globalThis.inputState, port = 1 } = {}) {\n        if (!inputState) throw new Error('GMTouchControls.mount: no inputState provided');\n        if (this.shouldShowControls() === false) {\n            return { unmount() {}, updateActiveJoystick() {} };\n        }\n\n        // === DOM ===\n        // Single overlay element positioned absolutely over the host, holding\n        // the joystick region on the left and the fire button on the right.\n        // Everything uses `touch-action: none` so browser gestures (pinch,\n        // scroll, double-tap zoom) don't interfere with game input.\n        const overlay = document.createElement('div');\n        overlay.className = 'gm-touch-overlay';\n\n        const joystickEl = document.createElement('div');\n        joystickEl.className = 'gm-touch-joystick';\n        const puckEl = document.createElement('div');\n        puckEl.className = 'gm-touch-joystick-puck';\n        joystickEl.appendChild(puckEl);\n\n        const fireEl = document.createElement('div');\n        fireEl.className = 'gm-touch-fire';\n        fireEl.textContent = '●';   // filled dot — reads as \"button\"\n\n        overlay.appendChild(joystickEl);\n        overlay.appendChild(fireEl);\n        hostEl.appendChild(overlay);\n\n        // === STATE ===\n        // Track active touch identifiers so multi-touch works: joystick and\n        // fire can be held simultaneously without either canceling the other.\n        // When a finger moves off its zone, we keep its identifier bound to\n        // the zone it started in — matches real d-pad/button behaviour.\n        let joyTouchId = null;\n        let fireTouchId = null;\n        let joyCenterX = 0;\n        let joyCenterY = 0;\n        const JOY_DEADZONE = 12;     // pixels from center where no direction registers\n        const JOY_MAX_OFFSET = 45;   // puck can move this far from center\n        const joyKey = port === 2 ? 'joystick2' : 'joystick1';\n        const btnKey = port === 2 ? 'button2'   : 'button1';\n\n        // === EVENT HANDLERS ===\n        // Refresh joystick center after any layout change (rotation, fullscreen).\n        function refreshJoyCenter() {\n            const rect = joystickEl.getBoundingClientRect();\n            joyCenterX = rect.left + rect.width / 2;\n            joyCenterY = rect.top + rect.height / 2;\n        }\n\n        function resetJoystickState() {\n            inputState[joyKey].up = false;\n            inputState[joyKey].down = false;\n            inputState[joyKey].left = false;\n            inputState[joyKey].right = false;\n            puckEl.style.transform = '';\n            joystickEl.classList.remove('gm-touch-active');\n        }\n\n        // Given a touch's page position relative to joystick center, update\n        // the four boolean directions on inputState AND move the puck. Uses\n        // an 8-way angular resolve with a small dead zone.\n        function updateJoystick(touchX, touchY) {\n            const dx = touchX - joyCenterX;\n            const dy = touchY - joyCenterY;\n            const dist = Math.hypot(dx, dy);\n\n            // Puck follows finger but clamped to a max radius\n            const clampedDist = Math.min(dist, JOY_MAX_OFFSET);\n            const puckX = dist > 0 ? (dx / dist) * clampedDist : 0;\n            const puckY = dist > 0 ? (dy / dist) * clampedDist : 0;\n            puckEl.style.transform = `translate(${puckX}px, ${puckY}px)`;\n\n            if (dist < JOY_DEADZONE) {\n                inputState[joyKey].up = false;\n                inputState[joyKey].down = false;\n                inputState[joyKey].left = false;\n                inputState[joyKey].right = false;\n                return;\n            }\n\n            // 8-way octant resolve. Angle 0 = right; positive = down.\n            // Boundaries at every 22.5° (halfway between adjacent octants).\n            const angle = Math.atan2(dy, dx);\n            const deg = (angle * 180 / Math.PI + 360) % 360;\n            inputState[joyKey].right = deg >= 292.5 || deg < 67.5;\n            inputState[joyKey].down  = deg >= 22.5  && deg < 157.5;\n            inputState[joyKey].left  = deg >= 112.5 && deg < 247.5;\n            inputState[joyKey].up    = deg >= 202.5 && deg < 337.5;\n        }\n\n        function onTouchStart(e) {\n            for (const t of e.changedTouches) {\n                const target = document.elementFromPoint(t.clientX, t.clientY);\n                if (!target) continue;\n                // Joystick — the whole left region is receptive so the user\n                // doesn't have to land precisely on the puck.\n                if (joyTouchId === null && (target === joystickEl || target === puckEl || joystickEl.contains(target))) {\n                    joyTouchId = t.identifier;\n                    refreshJoyCenter();\n                    joystickEl.classList.add('gm-touch-active');\n                    updateJoystick(t.clientX, t.clientY);\n                    e.preventDefault();\n                    continue;\n                }\n                // Fire button\n                if (fireTouchId === null && (target === fireEl || fireEl.contains(target))) {\n                    fireTouchId = t.identifier;\n                    inputState[btnKey] = true;\n                    fireEl.classList.add('gm-touch-active');\n                    e.preventDefault();\n                    continue;\n                }\n            }\n        }\n\n        function onTouchMove(e) {\n            for (const t of e.changedTouches) {\n                if (t.identifier === joyTouchId) {\n                    updateJoystick(t.clientX, t.clientY);\n                    e.preventDefault();\n                }\n                // Fire button is binary — no move handling needed for it\n            }\n        }\n\n        function onTouchEnd(e) {\n            for (const t of e.changedTouches) {\n                if (t.identifier === joyTouchId) {\n                    joyTouchId = null;\n                    resetJoystickState();\n                }\n                if (t.identifier === fireTouchId) {\n                    fireTouchId = null;\n                    inputState[btnKey] = false;\n                    fireEl.classList.remove('gm-touch-active');\n                }\n            }\n        }\n\n        // Attach at the overlay level (not window) so touches outside the\n        // controls don't accidentally trigger them.\n        overlay.addEventListener('touchstart', onTouchStart, { passive: false });\n        overlay.addEventListener('touchmove',  onTouchMove,  { passive: false });\n        overlay.addEventListener('touchend',   onTouchEnd,   { passive: false });\n        overlay.addEventListener('touchcancel', onTouchEnd,  { passive: false });\n\n        // Recompute joystick center on rotation/resize/fullscreen — the\n        // element moves around visually and getBoundingClientRect() lies\n        // if we cached it from before.\n        window.addEventListener('resize', refreshJoyCenter);\n        window.addEventListener('orientationchange', refreshJoyCenter);\n\n        return {\n            unmount() {\n                overlay.remove();\n                window.removeEventListener('resize', refreshJoyCenter);\n                window.removeEventListener('orientationchange', refreshJoyCenter);\n            },\n            // For hosts that dynamically change joystick port (unusual)\n            setPort(newPort) { /* reserved for later */ },\n        };\n    },\n};\n\nif (typeof globalThis !== 'undefined') {\n    globalThis.GMTouchControls = GMTouchControls;\n}\n</script>\n\n<script>\n// Chrome-free game player. Two run modes:\n//\n//   1. URL-driven — normal use. `?disk=<url>&file=<name>` fetches a .d64\n//      and picks a program off it. Shows a play-button overlay; the\n//      click starts the VM and unlocks the AudioContext (autoplay-policy\n//      compliant).\n//\n//   2. Embedded — the editor's \"Export Game\" flow patches the two\n//      EMBEDDED_ consts below with base64-encoded PRG + D64 bytes. When\n//      those aren't null, we skip the URL fetch entirely and decode the\n//      bytes locally. That's how the exported HTML is *literally*\n//      play.html with two strings changed — one source of truth for the\n//      player. See tools/bundle-standalone.js for the build path.\n//\n// URL params (mode 1 only, plus these two which work in both modes):\n//   disk            .d64 URL, or the magic word `demo` for the bundled demo\n//   file            program name on the disk (case-insensitive)\n//   nocredit=1      hides the gmc64.com corner link (must be exactly \"1\")\n//   poster_seconds  how long to simulate the game before rendering the\n//                   preview frame behind the play button. Default: 2.\n//                   Max: 10. Decimals allowed (rounded to 0.01s). `=0`\n//                   skips the poster entirely — canvas stays black.\n\n// Populated at Export time via string replacement — see\n// tools/bundle-standalone.js. Stay `null` in normal play.html use;\n// the exported HTML has them as base64 strings.\nconst EMBEDDED_PRG = null;\nconst EMBEDDED_D64 = null;\n\nconst disk = new GMDisk('player');\nlet audioContext = null;\nlet masterGain = null;\nlet vm = null;\nlet screen = null;\nlet charset = null;\nlet audioIndicator = null;\nlet currentProgramData = null;\nlet currentFileData = null;\nlet currentFileName = null;\nlet animationFrameToggle = false;\n\n// User volume 0..1. Shared localStorage key across editor + player so a\n// user's preference travels between the two contexts. Default: comfortable\n// mid-range so first-visit isn't loud, isn't silent.\nconst VOLUME_KEY = 'gmc64-volume';\nlet userVolume = parseFloat(localStorage.getItem(VOLUME_KEY));\nif (!isFinite(userVolume) || userVolume < 0 || userVolume > 1) userVolume = 0.75;\n\n// SFX_BASELINE is the pre-user-volume gain the host masterGain was pinned\n// at before we introduced the slider. Keep it as the \"100% user volume\"\n// ceiling so cranking to 100 doesn't blow out ears vs the old default.\nconst SFX_BASELINE = 0.3;\n// Handle to the mounted GMDiskPicker (assigned in init).\nlet picker = null;\n// Handle to the mounted touch controls (null until startGame, no-op on desktop).\nlet touchControls = null;\n\n// Input preset settings — persisted in localStorage. Different key from\n// the editor so per-context choices don't leak between them.\nconst INPUT_SETTINGS_KEY = 'gmc64-player-input';\nlet inputSettings = GMPlayerChrome.loadInputSettings(\n    INPUT_SETTINGS_KEY, GMPlayerChrome.DEFAULT_INPUT_SETTINGS);\n\n// Input state read by gmRuntime. Same shape as editor.html.\nconst inputState = {\n    joystick1: { up: false, down: false, left: false, right: false },\n    joystick2: { up: false, down: false, left: false, right: false },\n    button1: false,\n    button2: false\n};\n\nfunction decode16bit(lo, hi) { return lo + (hi << 8); }\n\nwindow.addEventListener('DOMContentLoaded', init);\n\nasync function init() {\n    charset = new gmCharset();\n\n    if (new URLSearchParams(location.search).get('nocredit') === '1') {\n        document.querySelector('.credit').style.display = 'none';\n    }\n\n    // Tag body with phone-layout class before any layout math runs so\n    // gameborder-h resolves against the mobile CSS from the first paint.\n    // Tablets keep the desktop layout (they have room for chrome).\n    if (GMTouchControls.isPhoneLayout()) {\n        document.body.classList.add('mobile-phone');\n    }\n\n    // Populate hamburger button icon (declared as empty in HTML). Pause\n    // icon initialized on first play state change.\n    document.getElementById('hamburgerBtn').innerHTML = GMPlayerChrome.ICONS.hamburger;\n\n    populateJoystickSelects();\n    setupVolumeSlider();\n\n    // Mount the shared disk picker inside the game border. Window-level\n    // drops are enabled here too so someone with a game already loaded\n    // can drag a fresh .d64 to swap games.\n    picker = GMDiskPicker.mount(document.getElementById('gameBorder'), {\n        extension: '/PRG',\n        // Promote dropped disks into the shared localStorage pool + make\n        // them the current disk. Other editors see the same pool.\n        disk,\n        windowDropEnabled: true,\n        onPickFile: (name, bytes, d64 /*, diskLabel */) => {\n            // gmParser needs loadFileByName to resolve multi-part sprite\n            // references etc. — module wired it too, but re-set here so\n            // we're consistent regardless of code path.\n            globalThis.loadFileByName = (n) => {\n                try { return d64.readFile(n); } catch (e) { return null; }\n            };\n            proceedWithProgram(name, bytes);\n        }\n    });\n\n    document.getElementById('hamburgerBtn').addEventListener('click', toggleSettingsPopup);\n    document.getElementById('playOverlay').addEventListener('click', startGame);\n    document.getElementById('fullscreenToggle').addEventListener('click', toggleFullscreen);\n    // Refresh fullscreen icon when the state actually changes (Escape key,\n    // browser gesture) so it doesn't stick showing \"enter fullscreen\"\n    // after the user has exited via a native path.\n    document.addEventListener('fullscreenchange', refreshFullscreenIcon);\n    document.addEventListener('webkitfullscreenchange', refreshFullscreenIcon);\n    refreshFullscreenIcon();\n\n    // Shared input listener — gates on vm being present and running so\n    // key presses before start / after end don't leak into inputState.\n    GMPlayerChrome.setupInputListeners({\n        inputState,\n        getPresets: () => inputSettings,\n        isEnabled: () => vm && vm.running\n    });\n\n    // Close settings popup on click-outside or Escape.\n    document.addEventListener('click', (e) => {\n        const popup = document.getElementById('settingsPopup');\n        if (!popup.classList.contains('active')) return;\n        const burger = document.getElementById('hamburgerBtn');\n        if (!popup.contains(e.target) && !burger.contains(e.target)) {\n            popup.classList.remove('active');\n        }\n    });\n    document.addEventListener('keydown', (e) => {\n        if (e.key !== 'Escape') return;\n        const popup = document.getElementById('settingsPopup');\n        if (popup.classList.contains('active')) popup.classList.remove('active');\n    });\n\n    await loadGame();\n}\n\nfunction toggleSettingsPopup(e) {\n    if (e) e.stopPropagation();   // don't trip the click-outside handler\n    document.getElementById('settingsPopup').classList.toggle('active');\n}\n\n// Volume slider — reads current userVolume, applies changes to both\n// audio paths (SFX via host masterGain, music via vm.setConfig →\n// _effectiveSongVolume), persists on 'input' so drags feel live.\nfunction setupVolumeSlider() {\n    const slider = document.getElementById('volumeSlider');\n    slider.value = Math.round(userVolume * 100);\n    slider.addEventListener('input', () => {\n        userVolume = slider.value / 100;\n        localStorage.setItem(VOLUME_KEY, String(userVolume));\n        if (masterGain) masterGain.gain.value = SFX_BASELINE * userVolume;\n        if (vm) vm.setConfig({ userVolume });\n    });\n}\n\n// Fill the joy1/joy2 dropdowns from the shared PRESET_LABELS. Runs once\n// at init. Selecting either dropdown updates inputSettings + persists.\nfunction populateJoystickSelects() {\n    for (const which of ['joy1', 'joy2']) {\n        const sel = document.getElementById(which + 'Sel');\n        sel.innerHTML = '';\n        for (const [value, label] of GMPlayerChrome.PRESET_LABELS) {\n            const opt = document.createElement('option');\n            opt.value = value;\n            opt.textContent = label;\n            sel.appendChild(opt);\n        }\n        sel.value = inputSettings[which];\n        sel.addEventListener('change', () => {\n            inputSettings = { ...inputSettings, [which]: sel.value };\n            GMPlayerChrome.saveInputSettings(INPUT_SETTINGS_KEY, inputSettings);\n        });\n    }\n}\n\n// Three entry modes:\n//   1. Embedded (Export): EMBEDDED_PRG / EMBEDDED_D64 populated → skip\n//      URL params entirely, decode bytes, jump straight to poster + play.\n//   2. URL-driven: `?disk=<url>` present. `file=` optional — missing\n//      falls back to auto-load (one PRG) or the program picker (2+).\n//   3. Bare visit (no disk, no embedded): show the drop-zone so the\n//      visitor can drop their own .d64.\nasync function loadGame() {\n    if (EMBEDDED_PRG && EMBEDDED_D64) {\n        const d64Bytes = _b64ToBytes(EMBEDDED_D64);\n        const prgBytes = _b64ToBytes(EMBEDDED_PRG);\n        const embeddedDisk = new D64(d64Bytes);\n        globalThis.loadFileByName = (name) => {\n            try { return embeddedDisk.readFile(name); } catch (e) { return null; }\n        };\n        proceedWithProgram('<embedded>', prgBytes);\n        return;\n    }\n\n    const params = new URLSearchParams(location.search);\n    if (!params.has('disk')) {\n        picker.showDropZone();\n        return;\n    }\n\n    const ok = await GMTools.loadDiskFromUrl({\n        diskUrl: params.get('disk'), disk\n    });\n    if (!ok) {\n        showPlayButtonError('invalid disk');\n        return;\n    }\n\n    // gmParser needs this to compose multi-part sprites that reference\n    // other files on the disk. Set up before any PRG parsing.\n    globalThis.loadFileByName = (name) => disk.disk.readFile(name);\n\n    const fileName = params.get('file');\n    if (!fileName) {\n        // No specific file requested — enumerate PRGs and auto-load if\n        // there's only one, or hand off to the picker for multiple.\n        const prgs = GMTools.listFilesByExtension(disk.disk, '/PRG');\n        if (prgs.length === 0) {\n            showPlayButtonError('no programs on disk');\n            return;\n        }\n        if (prgs.length === 1) {\n            proceedWithProgram(prgs[0], disk.disk.readFile(prgs[0]));\n            return;\n        }\n        picker.showProgramPicker(disk.disk, prgs, disk.diskFileName || params.get('disk'));\n        return;\n    }\n\n    const actualName = GMTools.findFileCaseInsensitive(disk.disk, fileName);\n    if (!actualName) {\n        showPlayButtonError('invalid file');\n        return;\n    }\n    if (!actualName.toUpperCase().endsWith('/PRG')) {\n        showPlayButtonError('invalid file type');\n        return;\n    }\n\n    const fileData = disk.disk.readFile(actualName);\n    if (!fileData) {\n        showPlayButtonError('invalid file');\n        return;\n    }\n\n    proceedWithProgram(actualName, fileData);\n}\n\n// Once we have a name + bytes for the program we want to run, this\n// commits it, kicks off the poster, and reveals the play button.\n// Shared by all three entry modes (embedded, URL, drop).\nfunction proceedWithProgram(name, bytes) {\n    currentFileName = name;\n    currentFileData = bytes;\n    currentProgramData = parseProgramData(bytes);\n    picker.hide();\n    document.getElementById('playOverlay').classList.add('active');\n    // Fire-and-forget — a poster failure never blocks the play button.\n    generatePoster();\n}\n\n// Decode a base64 string to a Uint8Array. Chunk-loop because atob\n// returns a binary string and we need byte codes.\nfunction _b64ToBytes(b64) {\n    const bin = atob(b64);\n    const out = new Uint8Array(bin.length);\n    for (let i = 0; i < bin.length; i++) out[i] = bin.charCodeAt(i);\n    return out;\n}\n\nfunction showPlayButtonError(text) {\n    const btn = document.getElementById('playButton');\n    btn.textContent = text;\n    btn.disabled = true;\n    btn.setAttribute('aria-label', text);\n    // The play overlay is hidden by default now — surface it so the\n    // error message is actually visible.\n    document.getElementById('playOverlay').classList.add('active');\n}\n\n// The play button is the user gesture that both starts the VM and\n// unlocks the AudioContext. Everything audio-related happens inside\n// this handler so browser autoplay policies stay satisfied.\nasync function startGame() {\n    if (!currentProgramData) return;\n    document.getElementById('playOverlay').classList.remove('active');\n\n    if (!screen) screen = new c64Screen('gameCanvas');\n    if (!vm) vm = new gmVM(screen);\n\n    if (!audioContext) {\n        audioContext = new (window.AudioContext || window.webkitAudioContext)();\n        masterGain = audioContext.createGain();\n        masterGain.gain.value = SFX_BASELINE * userVolume;\n        masterGain.connect(audioContext.destination);\n    }\n    if (audioContext.state === 'suspended') {\n        audioContext.resume();\n    }\n\n    // Push the persisted user volume into the fresh vm's config so the\n    // very first song starts at the right level (rather than defaulting\n    // to 1.0 and then getting corrected on the first slider tick).\n    vm.setConfig({ userVolume });\n\n    if (!audioIndicator) {\n        // Mount inside #gameControls so it flexes with the other icons.\n        // (The shared CSS defaults the indicator to position:absolute; our\n        // #gameControls .gm-audio-indicator override neutralises that.)\n        audioIndicator = new GMAudioIndicator(document.getElementById('gameControls'));\n        audioIndicator.bind({\n            getMuted: () => vm.config.audioMuted,\n            setMuted: (muted) => vm.setConfig({ audioMuted: muted }),\n            getAudioContext: () => audioContext,\n            onUnlock: () => {\n                if (vm && vm.currentSong) {\n                    try {\n                        vm.currentSong.stop();\n                        vm.currentSong.play();\n                        vm.currentSong.setVolume(vm._effectiveSongVolume());\n                    } catch (e) {\n                        console.warn('Failed to restart song after audio unlock:', e.message);\n                    }\n                }\n            }\n        });\n    }\n\n    // Reveal the control cluster (hidden until first play) and wire the\n    // pause button once. Icon reflects current vm.paused state.\n    document.getElementById('gameControls').style.display = '';\n    const pauseBtn = document.getElementById('pauseToggle');\n    if (!pauseBtn.dataset.wired) {\n        pauseBtn.dataset.wired = '1';\n        pauseBtn.addEventListener('click', togglePause);\n    }\n\n    // Mount touch controls on the play area (idempotent — no-op on desktop\n    // and if already mounted). We wait until startGame rather than mounting\n    // in init so the joystick doesn't appear on top of the play overlay.\n    if (!touchControls) {\n        touchControls = GMTouchControls.mount(\n            document.getElementById('playArea'),\n            { inputState, port: 1 });\n    }\n\n    // Re-parse so the real run gets a fresh mediaStore, unmutated by\n    // whatever the poster VM did.\n    const programData = parseProgramData(currentFileData);\n    const ast = buildAST(programData);\n    vm.loadProgram(ast, currentFileData);\n    // frameMs pinned to NTSC C64 rate (59.94Hz), catchup on so game speed\n    // is wall-clock consistent even under browser throttling.\n    vm.start({ opsPerFrame: 50, frameMs: 1000 / 59.94, catchup: true });\n    GMPlayerChrome.setPauseIcon(pauseBtn, false);\n}\n\nfunction togglePause() {\n    if (!vm) return;\n    if (vm.paused) vm.resume();\n    else vm.pause();\n    GMPlayerChrome.setPauseIcon(document.getElementById('pauseToggle'), vm.paused);\n}\n\n// Fullscreen toggle — targets documentElement so the game AND any floating\n// touch controls both scale into the fullscreen box. Uses webkit prefix\n// as fallback for iPad Safari, which supports Fullscreen API only under\n// that name. iOS iPhone Safari doesn't support it at all (silent no-op).\nfunction toggleFullscreen() {\n    const el = document.documentElement;\n    if (document.fullscreenElement || document.webkitFullscreenElement) {\n        (document.exitFullscreen || document.webkitExitFullscreen).call(document);\n    } else {\n        const req = el.requestFullscreen || el.webkitRequestFullscreen;\n        if (req) req.call(el);\n    }\n}\n\nfunction refreshFullscreenIcon() {\n    const btn = document.getElementById('fullscreenToggle');\n    if (!btn) return;\n    const active = !!(document.fullscreenElement || document.webkitFullscreenElement);\n    // \"Enter\" icon: outward arrows. \"Exit\" icon: inward arrows. Chosen for\n    // shape recognition rather than reading — the fine strokes render fine\n    // even in the reduced-opacity mobile chrome.\n    btn.innerHTML = active\n        ? `<svg viewBox=\"0 0 24 24\" xmlns=\"http://www.w3.org/2000/svg\" aria-hidden=\"true\">\n             <path d=\"M9 4 L9 9 L4 9 M15 4 L15 9 L20 9 M20 15 L15 15 L15 20 M4 15 L9 15 L9 20\"\n                   fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"\n                   stroke-linecap=\"round\" stroke-linejoin=\"round\"/>\n           </svg>`\n        : `<svg viewBox=\"0 0 24 24\" xmlns=\"http://www.w3.org/2000/svg\" aria-hidden=\"true\">\n             <path d=\"M4 9 L4 4 L9 4 M15 4 L20 4 L20 9 M20 15 L20 20 L15 20 M9 20 L4 20 L4 15\"\n                   fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"\n                   stroke-linecap=\"round\" stroke-linejoin=\"round\"/>\n           </svg>`;\n}\n\n// Kick off a poster render on the game canvas. Screen has to exist first\n// so the temp VM has something to draw on. Fire-and-forget — a poster\n// failure never blocks the user from starting the game.\nasync function generatePoster() {\n    if (!screen) screen = new c64Screen('gameCanvas');\n    const params = new URLSearchParams(location.search);\n    await GMPoster.generatePoster({\n        screen,\n        fileData: currentFileData,\n        posterSeconds: GMPoster.getPosterSeconds(params)\n    });\n}\n\n</script>\n</body>\n</html>\n";
